#include <iostream>
#include <queue>
#include <vector>
using namespace std;

// 定义四个方向的移动
const int dx[4] = {-1, 1, 0, 0};
const int dy[4] = {0, 0, -1, 1};

bool canReachEnd(int n, int m, vector<string>& maze) {
    // 初始化队列和访问标记
    queue<pair<int, int>> q;
    q.push({0, 0}); // 起点是 (0, 0)
    vector<vector<bool>> visited(n, vector<bool>(m, false));
    visited[0][0] = true;

    while (!q.empty()) {
        auto [x, y] = q.front();
        q.pop();

        // 如果到达终点
        if (x == n - 1 && y == m - 1) {
            return true;
        }

        // 遍历四个方向
        for (int i = 0; i < 4; i++) {
            int nx = x + dx[i];
            int ny = y + dy[i];

            // 检查边界和是否可访问
            if (nx >= 0 && nx < n && ny >= 0 && ny < m && maze[nx][ny] == '.' && !visited[nx][ny]) {
                visited[nx][ny] = true;
                q.push({nx, ny});
            }
        }
    }

    // 如果遍历结束仍未到达终点
    return false;
}

int main() {
    int n, m;
    cin >> n >> m;
    vector<string> maze(n);
    for (int i = 0; i < n; i++) {
        cin >> maze[i];
    }

    // 判断是否能到达终点
    if (canReachEnd(n, m, maze)) {
        cout << "Yes" << endl;
    } else {
        cout << "No" << endl;
    }

    return 0;
}
